THE RISK:
{
 "id": "compliance-serialization-zeroes-h1",
 "title": "A serialized cert-and-listing critical path zeroes H1 revenue — 'conservative ramp' is not linear in months",
 "narrative": "The YAM implicitly assumes the selling machine exists on day 1 of the 12-month window. But an intelligent PDU sold into CE must first clear a compliance stack the model only gestures at: CE (LVD/EMC), RoHS, WEEE producer registration (Germany's stiftung EAR is a named, dated gate), EORI customs registration, and the buyer-side pull-through of EU 2024/1364 (DC rating scheme, in force May 2024) and EED 2024/1791 KPI disclosures that operators now push down into vendor questionnaires. These gates are serialized — test slots before declaration, registration before listing, listing before quote. A two-quarter slip does not scale YAM by 50% linearly; it deletes the ramp's compounding front end, because the conservative ramp back-loads revenue into quarters that no longer exist.",
 "category": "execution",
 "targetNodes": [
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "The real EU entry stack is materially larger than the three regimes the ledger cites: WEEE, ROHS, FCC, EORI customs, plus the 2024 DC rating scheme and EED disclosure duties landing on operators and flowing into vendor requirements",
   "refs": [
    "digest:serviceable-benchmark#c10",
    "digest:serviceable-benchmark#c8",
    "digest:serviceable-benchmark#c9"
   ]
  },
  {
   "step": "propagation",
   "text": "Each gate precedes quoting eligibility; for a pre-launch venture the qualification clock and the harvest clock are the same 12 months, so a 2-quarter serialization consumes the highest-leverage half of the obtainable window",
   "refs": [
    "profile:Stage",
    "digest:serviceable-benchmark#c6",
    "ledger:serviceableFactor"
   ]
  },
  {
   "step": "model-impact",
   "text": "Effective Year-1 obtainable share halves or worse relative to the curated 0.03, independent of demand — the market is there, the vendor is not yet legally/commercially present in it",
   "refs": [
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "Compliance appears in the model as a static haircut inside serviceableFactor — a level, not a schedule. Because the funnel has no time axis, a delay risk masquerades as an already-priced reach discount, and 'conservative ramp' in the profile reads as if it already absorbs slippage.",
 "expectedObviousness": "medium",
 "falsifier": "A complete, dated compliance dossier (CE declaration, RoHS/WEEE registrations incl. stiftung EAR number, EORI) plus at least one distributor or operator listing in hand before the Year-1 clock starts.",
 "likelihood": {
  "value": 0.48,
  "rationale": "First-time EU market entry for networked electrical hardware routinely takes 2–4 quarters across test-lab lead times and national registrations; the venture is pre-launch with no evidence in the ledger that any of these artifacts exist yet. [evidence revision: Evidence confirms the gates exist and are serialized and precede commercial presence, supporting the mechanism's direction. But the load-bearing quantum — a full two-quarter slip — is undercut for a non-wireless PDU where CE (EMC+LVD, no Notified Body/RED) fits inside 2-12 weeks. WEEE authorized-rep appointment, EORI, and first-listing pull-through still consume meaningful serialized time, so a material (roughly one-quarter+) front-end erosion remains plausible for a pre-launch venture with no artifacts. Net slightly below prior 0.55.]",
  "basis": "evidence",
  "revisedFrom": 0.55
 },
 "perturbation": [
  {
   "nodeId": "obtainableFactor",
   "op": "scale",
   "value": 0.5,
   "note": "Two quarters of the Year-1 window consumed by serialized cert/registration/listing before first PO"
  }
 ],
 "indicators": [
  {
   "signal": "WEEE producer-registration processing time for new foreign entrants in Germany",
   "where": "stiftung EAR (stiftung-ear.de) published processing notes and applicant guidance",
   "threshold": ">10 weeks from application to registration number",
   "updates": "increases"
  },
  {
   "signal": "Test-slot lead times for LVD/EMC certification of power distribution hardware",
   "where": "TÜV Rheinland / TÜV Nord lab booking lead-time notices to vendors",
   "threshold": ">8 weeks to first available slot",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Commission a compliance-gap audit mapping every required artifact (per target country incl. non-EU Switzerland) to a dated critical path, before finalizing the Year-1 revenue plan",
   "type": "information",
   "voiNodeId": "obtainableFactor",
   "note": "Converts an unmodelled schedule risk into a plannable critical path; directly de-risks the Year-1 capture assumption"
  },
  {
   "action": "Start certification and national registrations in parallel now, pre-launch, treating the cert dossier as a launch gate rather than a post-launch task",
   "type": "operational",
   "voiNodeId": null,
   "note": "Moves the serialization out of the harvest window entirely"
  },
  {
   "action": "Contract a fulfilled-by-distributor arrangement where an established CE distributor's registrations (WEEE/EORI) cover initial shipments",
   "type": "contractual",
   "voiNodeId": null,
   "note": "Rents another firm's compliance stack for the first two quarters"
  }
 ],
 "evidenceStatus": "contested",
 "evidence": [
  {
   "title": "Which obligations do producers of electrical and electronic equipment have?",
   "sourceType": "industry-report",
   "publisher": "stiftung elektro-altgeräte register",
   "date": null,
   "excerpt": "Before you can sell electrical and electronic equipment in Germany, you have to be registered as a producer at the authority stiftung ear... If you have to be registered as a foreign company... you need to have a so-called authorised representative.",
   "url": "https://www.stiftung-ear.de/en/topic-areas/find-out-your-obligation-as-a-producer/which-obligations-do-producers-of-electrical-and-electronic-equipment-have/",
   "attached": true
  },
  {
   "title": "Full Process & Lead Time of EU CE Certification",
   "sourceType": "industry-report",
   "publisher": "Blue Asia Labs",
   "date": "2026-05-28",
   "excerpt": "EMC + LVD: AC-powered regular products. LVD takes 2 ~ 4 working days for long-term operation tests. Total lead time: 2 ~ 3 weeks.",
   "url": "https://www.blueasialabs.com/shouyehuandeng/full-process-amp-lead-time-of-eu-ce-certification",
   "attached": true
  },
  {
   "title": "Pre-Shipment Compliance Review for Importer of Record",
   "sourceType": "industry-report",
   "publisher": "TFTIOR",
   "date": "2026-05-21",
   "excerpt": "A product that looks secondary in a procurement list can be the product that stops the shipment... the issue date of a Declaration of Conformity matters. A declaration issued after shipment departure may not cleanly evidence compliance at the time of import.",
   "url": "https://tftior.com/pre-shipment-compliance-review-ior/",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.stiftung-ear.de/en/topic-areas/find-out-your-obligation-as-a-producer/which-obligations-do-producers-of-electrical-and-electronic-equipment-have/",
   "stance": "supports",
   "quote": "Before you can sell electrical and electronic equipment in Germany, you have to be registered as a producer at the authority stiftung ear."
  },
  {
   "url": "https://www.stiftung-ear.de/en/topic-areas/find-out-your-obligation-as-a-producer/which-obligations-do-producers-of-electrical-and-electronic-equipment-have/",
   "stance": "supports",
   "quote": "If you have to be registered as a foreign company because you would like to place equipment on the market in Germany, then you need to have a so-called authorised representative to do so."
  },
  {
   "url": "https://tftior.com/eu-ior/",
   "stance": "supports",
   "quote": "Authorities require a locally registered entity with an EORI number to act as the declarant and ensure products meet safety standards like CE."
  },
  {
   "url": "https://tftior.com/pre-shipment-compliance-review-ior/",
   "stance": "supports",
   "quote": "Accessories and PDUs carry real compliance risk. The product that looks secondary in a procurement list can be the product that stops the shipment."
  },
  {
   "url": "https://www.blueasialabs.com/shouyehuandeng/full-process-amp-lead-time-of-eu-ce-certification",
   "stance": "contradicts",
   "quote": "EMC + LVD: AC-powered regular products. LVD takes 2 ~ 4 working days for long-term operation tests. Total lead time: 2 ~ 3 weeks."
  },
  {
   "url": "https://markready.io/learn/how-to-get-ce-marking",
   "stance": "contradicts",
   "quote": "The process takes 4 to 12 weeks and costs €3,000 to €40,000 depending on your product's complexity."
  },
  {
   "url": "https://www.aestechno.com/en/ce-red-certification-iot/",
   "stance": "supports",
   "quote": "Realistic timelines: 4 to 6 weeks (pre-certified module, clean design) up to 3 to 6 months (custom RF, initial failure)."
  }
 ]
}

